export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
  const counts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const key = cellKey(cell[0], cell[1]);
      const entry = counts.get(key) ?? { cell, count: 0 };
      entry.count += 1;
      counts.set(key, entry);
    }
  }

  return [...counts.entries()]
    .filter(([key, { count }]) => survives(count, liveSet.has(key)))
    .map(([, { cell }]) => cell);
